INSERT INTO assistant_task VALUES(24,'VN-0C3188','2026-04-16 13:44:59.262560','Completed','send_money','{"amount": 5000.0, "currency": null, "location": null, "recipient": "Kamau", "document_type": null, "urgency": "low"}',15,'["Verify recipient''s details", "Confirm transfer amount and currency", "Process the transaction", "Notify the recipient of the transfer"]','Your money transfer of 5000 to Kamau is being processed.',replace('Subject: Task Confirmation: VM001\nDear User,\nYour request to send 5000 to Kamau has been received and is being processed.\nBest regards, Vunoh Global','\n',char(10)),'Vunoh Global: VM001 - Money transfer to Kamau initiated','Finance','The user''s request to ''send 5000 to Kamau'' triggered the ''send_money'' intent due to the presence of the keyword ''send'' and the mention of a specific amount and recipient. The ''send_money'' intent is the most appropriate for this context as it directly relates to transferring funds. The generated steps are necessary for the Kenyan operational environment as they ensure compliance with financial regulations and proper recipient verification. The ''Finance'' employee_assignment is chosen because it involves managing transactions and ensuring secure money transfers.');
INSERT INTO assistant_task VALUES(25,'VN-C7BCD5','2026-04-16 13:59:17.403547','Pending','verify_document','{"document_type": "title deed", "location": "Kiambu", "urgency": "high"}',95,'["Retrieve the title deed document", "Check the document''s authenticity with the relevant authorities", "Verify the plot''s details with the Kiambu county records", "Confirm the ownership and any outstanding liabilities"]','Your title deed verification request for a plot in Kiambu has been received and is being processed urgently.','Subject: Task Confirmation: VNTD001 - Verification of Title Deed for Kiambu Plot. Dear Client, we confirm receipt of your request to verify a title deed for a plot in Kiambu. Our legal team will expedite the process due to the high urgency.','Vunoh Global: VNTD001 - Your title deed verification for Kiambu plot is being processed.','Legal','The user''s request to ''verify a title deed'' triggered the ''verify_document'' intent. The mention of ''urgently'' indicates a high level of urgency. Given the context of verifying a title deed, which is a legal document, and the urgency of the task, the ''Legal'' department is the most suitable for handling this task. The steps outlined are necessary to ensure the title deed is genuine and to comply with the Kenyan legal environment, particularly the Land Registration Act.');
INSERT INTO assistant_task VALUES(26,'VN-CD9490','2026-04-16 14:00:00.844434','Completed','send_money','{"amount": 1500000.0, "currency": "KES", "location": null, "recipient": "Diamond Trust Bank", "document_type": null, "urgency": "medium"}',70,'["Verify recipient bank account details", "Initiate fund transfer via secure banking channels", "Notify recipient of successful transaction", "Update transaction records for auditing purposes"]','Your car purchase fund transfer of 1.5 Million KES to Diamond Trust Bank is being processed.',replace('Subject: Task Confirmation: VUNOH-001\nDear User,\nYour request to send 1.5 Million KES to Diamond Trust Bank for a car purchase has been received and is being processed.\nBest regards,\nVunoh Global Team','\n',char(10)),'Vunoh Global: VUNOH-001, Your car purchase fund transfer is being processed.','Finance','The user''s request to ''Send 1.5 Million KES to Diamond Trust Bank for a car purchase'' triggered the ''send_money'' intent due to the presence of the keyword ''Send'' and the specification of an amount and recipient. The ''send_money'' intent is the most appropriate for this context because it directly addresses the user''s need to transfer funds. The generated steps are necessary for the Kenyan legal and operational environment as they ensure compliance with financial regulations and facilitate a smooth transaction process.');
INSERT INTO assistant_task VALUES(27,'VN-9B18E1','2026-04-16 14:00:10.876498','Pending','get_airport_transfer','{"location": "JKIA", "time": "8:00 PM", "date": "tomorrow"}',5,'["Confirm flight details and arrival time", "Arrange for a driver and vehicle", "Coordinate pickup location and time", "Confirm pickup with the user"]','Your airport pickup from JKIA has been arranged for tomorrow at 8:00 PM.',replace('Subject: Task Confirmation: Airport Transfer\nDear User, your airport pickup from JKIA has been arranged for tomorrow at 8:00 PM. Please confirm your flight details.','\n',char(10)),'Vunoh Global: Your JKIA pickup is scheduled for tomorrow at 8:00 PM','Operations','The user''s request to be picked up from JKIA tomorrow at 8:00 PM triggered the ''get_airport_transfer'' intent. The keywords ''pick me up'' and ''JKIA'' specifically indicated a need for transportation services from the airport. Given the nature of the task, which involves logistical arrangements, the ''Operations'' team is the most suitable for handling this request. The necessary steps include confirming the user''s flight details, arranging for a driver, and ensuring timely pickup.');
INSERT INTO assistant_task VALUES(28,'VN-C7CECB','2026-04-16 14:00:25.079518','Pending','send_money','{"amount": 500.0, "currency": "USD", "location": null, "recipient": "Peter Kamau", "document_type": null, "urgency": "medium"}',15,'["Verify recipient''s details", "Check available funds", "Initiate transfer", "Confirm transaction"]','Your money transfer request to Peter Kamau for school fees has been received and is being processed.',replace('Subject: Task Confirmation: VN001\nDear Sir/Madam,\nYour request to transfer 500 USD to Peter Kamau for school fees has been received and is being processed.\nBest regards,\nVunoh Global Team','\n',char(10)),'Vunoh Global: VN001 - Money transfer request received','Finance','The user''s request to ''Transfer 500 USD to Peter Kamau for school fees'' triggered the ''send_money'' intent due to the presence of keywords ''Transfer'' and ''USD'', indicating a financial transaction. The ''send_money'' intent is the most appropriate for this context as it involves moving funds from one party to another. The generated steps are necessary for the Kenyan legal environment as they ensure compliance with financial regulations and proper documentation. The ''Finance'' employee_assignment is chosen because it involves handling monetary transactions, which is a key responsibility of the finance team.');
