INSERT INTO assistant_task VALUES(53,'VN-732089','2026-04-18 19:46:30.981309','Pending','send_money','{"amount": 1000.0, "currency": "KES", "location": null, "recipient": "bro", "document_type": null, "urgency": "medium"}',5,'["Verify recipient''s bank details", "Confirm transfer amount", "Initiate transfer", "Notify sender of transfer status"]',replace('VN-732089 — We''ve received your request to send 1k to your bro. We''ll verify the details and initiate the transfer. 📊\nPlease confirm the recipient''s bank details.','\n',char(10)),replace('Subject: Task Confirmation: VN-732089\nDear User,\nWe have received your request to send 1k to your brother. We will verify the recipient''s details and proceed with the transfer.\nPlease find the details of the next steps below.\nBest regards, Vunoh Team','\n',char(10)),'VN-732089 Send 1k to bro','Finance',replace('- The user''s message contains the phrase ''send my bro'' which indicates a transfer of funds.\n- The amount ''1k'' is explicitly mentioned, implying a transaction of 1000 units, likely in Kenyan Shillings (KES) given the context.\n- The recipient is mentioned as ''bro'', indicating a familial relationship, which is a common scenario for money transfers within Kenya.\n- The intent ''send_money'' is chosen over alternatives like ''hire_service'' because the context clearly points to a financial transaction.\n- The employee_assignment is Finance because money transfers are typically handled by the finance team, especially in a Kenyan context where such transactions are frequent and regulated.\n- In the Kenyan context, verifying the recipient''s details is crucial to avoid fraud, especially when transferring large amounts like 1k.\n- The urgency is set to medium as there''s no explicit mention of the transfer being time-sensitive, but prompt action is usually expected in such familial transactions.\n- Local verification of the recipient''s identity and bank details will be necessary to facilitate the transfer securely.','\n',char(10)));
INSERT INTO assistant_task VALUES(54,'VN-D43509','2026-04-18 19:47:21.325509','Pending','send_money','{"amount": 18500.0, "currency": "USD", "location": "Nairobi", "recipient": "brother", "document_type": null, "urgency": "high"}',90,'["Verify recipient details", "Check for potential fraud risks", "Initiate money transfer", "Notify user of transfer status"]','VN-D43509 — We''ve received your request to send USD 18,500 to your brother in Nairobi. We''ll verify the details and initiate the transfer ASAP 📈',replace('Subject: Task Confirmation: VN-D43509\nDear User,\nWe have received your request to send USD 18,500 to your brother in Nairobi. We will verify the recipient''s details and initiate the transfer as soon as possible.\nBest regards, Vunoh Global Assistant','\n',char(10)),'VN-D43509 Send USD 18,500 to brother in Nairobi','Finance',replace('- The user explicitly mentions ''send USD 18,500'' which triggers the send_money intent.\n- The mention of ''urgently'' indicates a high level of urgency.\n- The recipient is the user''s brother, which is a common recipient for money transfers in the Kenyan context.\n- The employee_assignment is Finance because send_money tasks require financial expertise, especially for large and urgent transactions like this one in the Kenyan market.\n- The Kenyan context is relevant here due to the potential for fraud and the need for local verification of the recipient''s details, such as their phone number.\n- The use of a specific phone number (071234579) for the recipient suggests a personal transfer, which is a common practice in Kenya.\n- Risk signals include the large amount of money being transferred and the urgency of the transaction, which may indicate a potential fraud risk.','\n',char(10)));
INSERT INTO assistant_task VALUES(55,'VN-372279','2026-04-18 19:47:43.876972','Pending','verify_document','{"amount": null, "currency": null, "location": "Kajiado", "recipient": null, "document_type": "land title deed", "urgency": "high"}',95,'["Receive and review the land title deed document", "Verify the document with the relevant Kenyan authorities", "Check for any discrepancies or potential fraud", "Provide a report on the verification outcome"]',replace('VN-372279 — We''ve received your request to verify a land title deed for plot 1842 in Kajiado. Our Legal team will handle this urgent matter. 📝\nWe will keep you updated on the progress.','\n',char(10)),replace('Subject: Task Confirmation: VN-372279\nDear [User],\nWe acknowledge receipt of your request to verify a land title deed for plot 1842 in Kajiado. This is an urgent matter that our Legal team will attend to promptly.\nPlease expect updates on the verification process.\nBest regards,\nVunoh Global Assistant','\n',char(10)),'VN-372279 Land title deed verification initiated','Legal',replace('- The user explicitly mentions ''verify a land title deed'', which directly triggers the verify_document intent.\n- The mention of ''plot 1842'' and ''Kajiado'' provides specific details necessary for the verification process.\n- The urgency is high due to the user stating ''it’s urgent'', indicating a need for prompt action.\n- In the Kenyan context, land title deeds are critical documents that require thorough verification to prevent fraud and ensure legitimate ownership.\n- The employee_assignment is Legal because document verification, especially for land titles, involves legal expertise and understanding of Kenyan property laws.\n- A risk signal noticed is the potential for fraud in land transactions, making thorough verification crucial.\n- Local verification processes in Kenya may involve checking with the Ministry of Lands or local land registries, highlighting the importance of local knowledge in this process.','\n',char(10)));
INSERT INTO assistant_task VALUES(56,'VN-4CC776','2026-04-18 19:48:08.457005','Pending','hire_service','{"amount": 0.0, "currency": null, "location": "Westlands", "recipient": null, "document_type": null, "urgency": "medium"}',10,'["Verify the plumber''s credentials and experience", "Coordinate with the plumber to schedule the service in Westlands", "Ensure the plumber has the necessary equipment to fix the leaking pipe", "Follow up with the user to confirm the service was performed satisfactorily"]',replace('VN-4CC776 — We''ve received your request to hire a plumber in Westlands. \nWe''ll coordinate the service and keep you updated. \nPlease let us know if you have any further questions. 🚧','\n',char(10)),replace('Subject: Task Confirmation: VN-4CC776\nDear [User],\nWe are writing to confirm that we have received your request to hire a plumber in Westlands to fix a leaking pipe.\nWe will coordinate the service and ensure it is performed to your satisfaction.\nPlease do not hesitate to contact us if you have any further questions or concerns.\nBest regards,\n[Your Name]','\n',char(10)),'VN-4CC776 Plumber hired for Westlands','Operations',replace('- The user''s request to ''hire a plumber'' triggered the hire_service intent.\n- This intent is correct because the user explicitly asked for a service to be performed, as opposed to sending money or verifying a document.\n- The location ''Westlands'' was extracted as it is crucial for coordinating the service in the Kenyan context.\n- The employee_assignment is Operations because hiring a plumber requires logistical coordination, which is typical of operations tasks in Kenya.\n- The urgency is medium because the user requested the service ''this week'', implying some time sensitivity but not extreme urgency.\n- In the Kenyan context, hiring a plumber in Westlands requires local verification of the plumber''s credentials and service coordination realities such as traffic and availability.\n- Risk signals include the potential for fraud if the plumber is not properly vetted, highlighting the need for Operations to handle the task.\n- The Kenyan context also dictates that Operations should be aware of local plumbing regulations and standards to ensure the service is performed correctly.','\n',char(10)));
INSERT INTO assistant_task VALUES(57,'VN-D5FF1C','2026-04-18 19:48:43.882083','Pending','send_money','{"amount": 0.0, "currency": null, "location": null, "recipient": null, "document_type": null, "urgency": "high"}',5,'["Verify recipient details", "Confirm transaction amount and currency", "Process the money transfer", "Notify the user of the transaction status"]','VN-D5FF1C — We''ve received your urgent money transfer request. Please provide recipient details and amount for processing. 📈',replace('Subject: Task Confirmation: VN-D5FF1C\nDear User,\nWe have received your request to send money urgently. To proceed, please provide the recipient''s details and the transaction amount.\nBest regards, Vunoh Global Assistant','\n',char(10)),'VN-D5FF1C Send money: provide recipient & amount','Finance',replace('- The user explicitly mentions ''send money'', which directly triggers the send_money intent.\n- The phrase ''urgently'' and ''as soon as possible'' indicates a high level of urgency.\n- The lack of specific details about the recipient, amount, or currency suggests that further clarification is needed.\n- In the Kenyan context, urgent money transfers are common, but they also pose a higher risk of fraud, emphasizing the need for verification.\n- The Finance team is the correct assignment for this task because they handle monetary transactions in Kenya.\n- The high urgency of the request is a risk signal that needs to be carefully managed to prevent potential fraud.\n- Local verification of the recipient''s details will be crucial to ensure the transaction''s legitimacy and safety.','\n',char(10)));
INSERT INTO assistant_task VALUES(58,'VN-31B106','2026-04-18 19:49:06.048630','Pending','get_airport_transfer','{"amount": null, "currency": null, "location": "JKIA to Westlands", "recipient": null, "document_type": null, "urgency": "medium"}',5,'["Confirm the pickup details with the user", "Assign a suitable vehicle for the transfer", "Coordinate with the driver for the pickup", "Ensure the driver is aware of the pickup time and location"]',replace('VN-31B106 — Your airport pickup from JKIA to Westlands is arranged for tomorrow at 7:00 AM. We will have a vehicle suitable for two people and two large suitcases. 🚗\nPlease confirm if these details are correct.','\n',char(10)),replace('Subject: Task Confirmation: VN-31B106\nDear User,\nYour request for an airport pickup from JKIA to Westlands has been arranged for tomorrow at 7:00 AM. The vehicle assigned can accommodate two people and two large suitcases.\nPlease let us know if these arrangements meet your requirements.\nBest regards, Vunoh Global Assistant','\n',char(10)),'VN-31B106 Airport pickup JKIA to Westlands tomorrow 7:00 AM','Operations',replace('- The user explicitly requested an airport pickup, which aligns with the get_airport_transfer intent.\n- The mention of ''JKIA'' and ''Westlands'' indicates a need for local transportation in Kenya, making get_airport_transfer the most suitable choice.\n- The details about ''two people'' and ''two large suitcases'' are crucial for service coordination, ensuring the assigned vehicle can accommodate the passengers and their luggage.\n- The employee_assignment is set to Operations because this team handles logistical tasks, such as arranging transportation in the Kenyan context.\n- The Kenyan context is relevant here due to the need for local verification of the pickup location and the coordination of services like airport transfers, which may involve understanding local traffic patterns and regulations.\n- Risk signals include the need for timely pickup and the potential for traffic congestion, which could impact the service quality.\n- The specificity of the pickup time (''7:00 AM tomorrow'') and the number of passengers and suitcases indicates a need for precise planning and execution by the Operations team.','\n',char(10)));
